class Solution:
    def maxProductPath(self, grid):
        m, n = len(grid), len(grid[0])
        best = [None]

        def dfs(i, j, prod):
            if i == m - 1 and j == n - 1:
                if best[0] is None or prod > best[0]:
                    best[0] = prod
                return
            if i + 1 < m:
                dfs(i + 1, j, prod * grid[i + 1][j])
            if j + 1 < n:
                dfs(i, j + 1, prod * grid[i][j + 1])

        dfs(0, 0, grid[0][0])
        res = best[0]
        return -1 if res < 0 else res % (10 ** 9 + 7)

