var maxProductPath = function(grid) {
    const MOD = 1000000007;
    const m = grid.length, n = grid[0].length;
    const maxdp = Array.from({length: m}, () => new Array(n).fill(0));
    const mindp = Array.from({length: m}, () => new Array(n).fill(0));
    maxdp[0][0] = mindp[0][0] = grid[0][0];
    for (let j = 1; j < n; j++) maxdp[0][j] = mindp[0][j] = maxdp[0][j - 1] * grid[0][j];
    for (let i = 1; i < m; i++) maxdp[i][0] = mindp[i][0] = maxdp[i - 1][0] * grid[i][0];
    for (let i = 1; i < m; i++) {
        for (let j = 1; j < n; j++) {
            const cands = [maxdp[i - 1][j] * grid[i][j], maxdp[i][j - 1] * grid[i][j],
                           mindp[i - 1][j] * grid[i][j], mindp[i][j - 1] * grid[i][j]];
            maxdp[i][j] = Math.max(...cands);
            mindp[i][j] = Math.min(...cands);
        }
    }
    const res = maxdp[m - 1][n - 1];
    return res < 0 ? -1 : res % MOD;
};
